// Adzuna doesn't handle long OR queries well, so we run multiple searches
const queries = [
  'machine learning',
  'computer vision',
  'deep learning',
  'software engineer',
  '3D engineer',
  'rendering engineer',
  'python developer'
];

const appId = $env.ADZUNA_APP_ID;
const appKey = $env.ADZUNA_KEY;
const allResults = [];

for (const q of queries) {
  try {
    const url = `https://api.adzuna.com/v1/api/jobs/fr/search/1?app_id=${appId}&app_key=${appKey}&results_per_page=20&what=${encodeURIComponent(q)}&where=France&max_days_old=7&content-type=application/json`;
    const response = await this.helpers.httpRequest({ method: 'GET', url, json: true });
    if (response.results) {
      allResults.push(...response.results);
    }
  } catch(e) {
    // Skip failed queries
  }
}

return [{ json: { results: allResults, count: allResults.length, __CLASS__: 'Adzuna::API::Response::JobSearchResults' } }];

// SerpAPI Google Jobs requires hl=fr&gl=fr for French results
// Run multiple queries to maximize coverage (free tier: 100 searches/month)
const queries = [
  'computer vision engineer',
  'machine learning engineer',
  'software engineer python',
  'ingenieur deep learning'
];

const apiKey = $env.SERPAPI_KEY;
const allJobs = [];

for (const q of queries) {
  try {
    const url = `https://serpapi.com/search.json?engine=google_jobs&q=${encodeURIComponent(q)}&location=Paris,+France&hl=fr&gl=fr&chips=date_posted:week&api_key=${apiKey}`;
    const response = await this.helpers.httpRequest({ method: 'GET', url, json: true });
    if (response.jobs_results) {
      allJobs.push(...response.jobs_results);
    }
  } catch(e) {
    // Skip failed queries
  }
}

return [{ json: { jobs_results: allJobs, count: allJobs.length } }];

// Normalize jobs from all three sources into a common format
// Safely get data from each source — handle cases where a node failed or returned nothing
let adzunaItems = [];
try { adzunaItems = $('Adzuna Job Search').first().json.results || []; } catch(e) { /* source unavailable */ }
let serpItems = [];
try { serpItems = $('Google Jobs via SerpAPI').first().json.jobs_results || []; } catch(e) { /* source unavailable */ }
const jobs = [];
const seen = new Set();

// Helper to create a dedup key
function dedupKey(title, company) {
  return `${(title || '').toLowerCase().trim()}|${(company || '').toLowerCase().trim()}`;
}

// Normalize Adzuna
for (const job of adzunaItems) {
  const key = dedupKey(job.title, job.company?.display_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.title || '',
    company: job.company?.display_name || '',
    location: job.location?.display_name || '',
    description: job.description || '',
    url: job.redirect_url || '',
    salary_min: job.salary_min || null,
    salary_max: job.salary_max || null,
    source: 'Adzuna',
    date_posted: job.created || '',
  });
}

// Normalize SerpAPI (Google Jobs)
for (const job of serpItems) {
  const key = dedupKey(job.title, job.company_name);
  if (seen.has(key)) continue;
  seen.add(key);

  // Extract salary from extensions if available
  let salaryInfo = null;
  if (job.detected_extensions?.salary) {
    salaryInfo = job.detected_extensions.salary;
  }

  jobs.push({
    title: job.title || '',
    company: job.company_name || '',
    location: job.location || '',
    description: job.description || '',
    url: job.apply_options?.[0]?.link || job.share_link || '',
    salary_min: null,
    salary_max: null,
    salary_text: salaryInfo,
    source: 'Google Jobs',
    date_posted: job.detected_extensions?.posted_at || '',
  });
}

return jobs.map(j => ({ json: j }));

// Filter out already-processed jobs, then limit batch to 5 per run
const MAX_PER_RUN = 25;

// Build dedup sets from existing sheet rows
const existingTitleCompany = new Set();
const existingUrls = new Set();
let sheetRowCount = 0;

try {
  const sheetItems = $('Read Existing Jobs').all();
  sheetRowCount = sheetItems.length;

  for (const item of sheetItems) {
    const d = item.json;
    if (!d || Object.keys(d).length === 0) continue;

    // Primary dedup key: role|company (handles both column name casings)
    const role = String(d['Role'] || d['role'] || d['Title'] || d['title'] || '').toLowerCase().trim();
    const company = String(d['Company'] || d['company'] || '').toLowerCase().trim();
    if (role || company) {
      existingTitleCompany.add(`${role}|${company}`);
    }

    // Secondary dedup key: apply URL
    const url = String(d['Apply URL'] || d['apply_url'] || d['URL'] || d['url'] || '').trim();
    if (url && url !== 'N/A' && url.length > 5) {
      existingUrls.add(url);
    }
  }
} catch(e) {
  // Do NOT silently swallow — log so we can debug
  console.log('[Filter] WARNING: Could not read existing jobs: ' + e.message);
}

console.log(`[Filter] Sheet: ${sheetRowCount} rows → ${existingTitleCompany.size} title|company keys, ${existingUrls.size} URLs`);

const allNormalized = $('Normalize & Deduplicate').all();

const newJobs = allNormalized.filter(item => {
  const j = item.json;
  const titleKey = `${(j.title || '').toLowerCase().trim()}|${(j.company || '').toLowerCase().trim()}`;
  const url = (j.url || '').trim();

  if (existingTitleCompany.has(titleKey)) return false;
  if (url && existingUrls.has(url)) return false;
  return true;
});

console.log(`[Filter] ${allNormalized.length} normalized → ${newJobs.length} new after dedup (max ${MAX_PER_RUN})`);

if (newJobs.length === 0) return [];
return newJobs.slice(0, MAX_PER_RUN);

// ── Groq tailoring (30 RPM, 1000 RPD, 100K TPD free tier) ───────────────────
const items = $input.all();
const apiKey = $env.GROQ_API_KEY;
const MODEL = 'llama-3.3-70b-versatile';

async function tailorJob(item) {
  const job = item.json;
  const systemPrompt = 'You are a resume tailoring assistant. You always respond with valid JSON only, no markdown.';
  const userPrompt = `Given a job posting and a candidate resume, produce a tailored version that reorders and reweights content to match the job.

JOB POSTING:
Title: ${job.title}
Company: ${job.company}
Description: ${(job.description || '').substring(0, 2000)}
Identify and incorporate relevant ATS keywords from the job description.

CANDIDATE EXPERIENCE (choose and reorder the most relevant):

1. Computer Vision R&D Engineer | GoPro | Paris, France | Mar. 2025 -- Sep. 2025
   - Architected a Sim-to-Real deep learning pipeline to solve parallax artifacts in dual-lens 360 degree image stitching.
   - Developed a procedural generation engine in Blender (Python API) to render photorealistic synthetic datasets.
   - Engineered a custom PyTorch model; validated with ML & Algorithm teams to outperform the production baseline.
   - Achieved >50% reduction in processing time over the legacy algorithm while minimizing seam artifacts.

2. Lead Founding Engineer & CTO | BargMe Startup | Remote | Jan. 2023 -- Nov. 2024
   - Engineered a vision-integrated product recognition pipeline, processing real-time mobile camera input to trigger algorithmic recommendations.
   - Developed the recommendation logic that generates cost-optimized alternative shopping lists based on queries.
   - Managed product lifecycle from research to deployment on Debian VPS, balancing backend latency with mobile constraints.

3. Technical Educator & 3D Specialist | SkillDino (InspirationTuts) | Remote | Jan. 2022 -- Dec. 2023
   - Authored tutorials on 3D Computer Vision (Photogrammetry, NeRFs) for an audience of 300,000+ subscribers.
   - Produced content bridging 3D software (Blender, Unity) and AI (OpenCV), simplifying complex research papers.

PROJECTS (choose and reorder the most relevant):

1. ASYEL: Sign Language Translation | Deep Learning, LSTM, Time-Series | Apr. 2022
   - Architected a gesture-to-speech translation pipeline using LSTM networks to classify live sign language sequences.
   - Solved data scarcity by recording a custom dataset, handling motion capture to feature extraction.
   - Won 2nd Prize at the National Innovation Competition.

2. Autonomous Safety & Fall Detection | Python, Pose Estimation, Edge AI | Nov. 2021
   - Developed an AI safety module for robotic vacuums to detect unattended incidents using Skeleton Tracking.
   - Designed human-in-the-loop verification: AI waits for an OK gesture to cancel alerts, reducing false positives.
   - Awarded 1st Prize at the Google DevFest AI Hackathon.

3. Real-Time Driver Monitoring (ADAS) | Python, MediaPipe 3D, OpenCV | Sep. 2021
   - Engineered a drowsiness/distraction detection system using 3D Facial Mesh to track 468 landmarks in real-time.
   - Implemented geometric analysis of facial vectors to calculate Eye Aspect Ratio (EAR) and yawning frequency.
   - Selected as Judges Favorite capstone project at Samsung Innovation Campus.

SKILLS (reorder categories and items by relevance to this job):
- Computer Vision & 3D: OpenCV, MediaPipe, YOLO, Optical Flow, Stereo Vision, Multi-view Geometry, Depth Est.
- Deep Learning: PyTorch/TensorFlow, CNNs (U-Net, ResNet), Vision Transformers, GANs, LSTMs, Custom Loss Design, Model Optimization
- 3D Graphics & Sim: Blender (Procedural Generation, Python API, Physics), Unity, Unreal Engine, Ray Tracing
- Software Engineering: Python (Expert), C++, C, TypeScript/JavaScript, SQL, Git, Docker, Linux, AWS, ONNX
- Data Science: NumPy, Pandas, Scikit-learn, Matplotlib, Seaborn, Jupyter

RULES:
- NEVER fabricate experience — only reframe and reorder existing achievements
- Reorder experiences and projects by relevance to THIS job (most relevant first)
- You may omit less relevant experiences/projects if space is tight (keep at least 2 experiences and 2 projects)
- Reword bullet points to emphasize aspects relevant to the job
- Reorder skills categories and items within them by relevance
- Incorporate ATS keywords naturally into bullet points

Respond ONLY with valid JSON:
{"company": "<company>", "role": "<title>", "ats_keywords": ["..."], "experiences": [{"title": "...", "dates": "...", "company": "...", "location": "...", "bullets": ["..."]}], "projects": [{"name": "...", "tech": "...", "dates": "...", "bullets": ["..."]}], "skills": [{"category": "...", "items": "..."}]}`;

  const body = {
    model: MODEL,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    temperature: 0.3,
    response_format: { type: 'json_object' }
  };

  const retryDelays = [5000, 15000, 30000];
  for (let attempt = 0; attempt <= 3; attempt++) {
    try {
      const response = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.groq.com/openai/v1/chat/completions',
        body, json: true,
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` }
      });
      const text = response.choices?.[0]?.message?.content;
      if (!text) throw new Error('No response from Groq for tailoring');
      const tailored = JSON.parse(text);
      return { json: { ...job, tailored_resume: tailored } };
    } catch(e) {
      const is429 = e.message?.includes('429');
      if (is429 && attempt < 3) { await new Promise(r => setTimeout(r, retryDelays[attempt])); continue; }
      throw e;
    }
  }
}

const results = [];
for (let i = 0; i < items.length; i++) {
  const result = await tailorJob.call(this, items[i]);
  results.push(result);
}
return results;

// Call the PDF microservice to generate the tailored resume PDF
const job = $input.item.json;
const tailored = job.tailored_resume;

if (!tailored) throw new Error('No tailored_resume data found');

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://pdf-service:3456/',
  body: JSON.stringify(tailored),
  headers: { 'Content-Type': 'application/json' },
  encoding: 'arraybuffer',
  returnFullResponse: true
});

const headers = response.headers || {};
const filename = headers['x-filename'] || `Riad_Boussoura_CV_${(job.company || 'Company').replace(/[^\w-]/g, '_')}.pdf`;
const pdfBuffer = Buffer.isBuffer(response.body) ? response.body : Buffer.from(response.body);

return {
  json: {
    ...job,
    pdf_filename: filename
  },
  binary: {
    data: await this.helpers.prepareBinaryData(pdfBuffer, filename, 'application/pdf')
  }
};

// Prepare row data for Google Sheet logging
const drive = $input.item.json;
const driveId = drive.id || drive.fileId || '';

// Get job data -- try paired-item linking first, fallback to index
let job = {};
try {
  job = $('Generate PDF').item.json;
} catch(e) {
  try {
    const allPdfItems = $('Generate PDF').all();
    job = allPdfItems[$itemIndex]?.json || allPdfItems[0]?.json || {};
  } catch(e2) {
    console.log('[PrepareRow] WARNING: Could not retrieve job data: ' + e2.message);
  }
}

// ATS keywords come from the tailoring LLM output (not scoring)
const tailored = job.tailored_resume || {};
const atsKw = Array.isArray(tailored.ats_keywords) ? tailored.ats_keywords.join(', ') : '';

return {
  json: {
    'Date': new Date().toISOString().split('T')[0],
    'Company': job.company || '',
    'Role': job.title || '',
    'Location': job.location || '',
    'Source': job.source || '',
    'Apply URL': job.url || '',
    'Score': '',
    'Verdict': 'Pending Review',
    'Rationale': '',
