    'Resume PDF': driveId ? `https://drive.google.com/file/d/${driveId}/view` : '',
    'Highlighted Skills': '',
    'ATS Keywords': atsKw,
    'Salary Range': job.salary_min ? `${job.salary_min} - ${job.salary_max}` : (job.salary_text || 'N/A'),
    'Hiring Manager': '',
    'Notes': ''
  }
};
